// Discovery v2: build a localized keyword-generation prompt by target. Returns candidates
// only (no DB write) — the UI lets the user pick which to queue. See specs/search-led-discovery.md.
const b=($('Webhook').first().json.body)||{};
const target=String(b.target||'clubs');
const country=String(b.country||'').trim();
const count=Math.max(5,Math.min(120,Number(b.count)||40));
const focus=String(b.focus||'').trim();
const breadth=String(b.breadth||'specific');
const cities=Array.isArray(b.cities)?b.cities:[];
let prompt;
if(target==='tournaments'){
  prompt='The input is: "'+country+'". It is EITHER a LOCATION (a country or city) OR a specific TOURNAMENT NAME. If it is a LOCATION: generate about '+count+' DISTINCT localized web-search queries to discover volleyball TOURNAMENTS held there, mixing the local-language word for tournament/cup/championship (torneo, coppa, Turnier, Pokal, turniej, mistrzostwa, cup, championship, open, memorial) with volleyball terms and levels (youth, U18, junior, club, regional, beach). If it is a TOURNAMENT NAME: generate 5-10 query variations to find THAT tournament official site / participating-teams / results / entry-list page (the name combined with teams/participants/results/standings and recent years). Each query should surface a SPECIFIC tournament event site with a participating-teams list (NOT news articles or a federation calendar). Respond ONLY with compact JSON {"keywords":[{"q":string,"lang":string}]}, lang = 2-letter code. No prose, no code fences.';
} else if(breadth==='broad'){
  prompt='Generate BROAD, high-recall web-search queries to discover MANY volleyball CLUB websites in '+country+'.'+(focus?(' Focus specifically on: '+focus+'.'):'')+' Each query must be a GENERAL search (NOT tied to a single city), in the LOCAL language(s) of the country (Italy: pallavolo; Germany/Austria/Switzerland: Volleyball; Poland: siatkowka; Spain: voleibol; France: volley-ball; Greece: petosfairisi; otherwise English).'+' Vary the angle across the set: club/Verein/klub/societa/asd, youth/Jugend/junior/U16/U18 and level words, list/directory/clubs words, and broad REGIONS (Bundeslaender/regioni/voivodeships) - NOT specific cities.'+' These queries will be PAGINATED (several result pages each), so favour breadth and recall over precision; directories and lists in the results are fine.'+' Produce about '+count+' DISTINCT broad queries. Respond ONLY with compact JSON {\"keywords\":[{\"q\":string,\"lang\":string}]} where lang is the 2-letter language code of q. No prose, no code fences.';
} else {
  prompt='Generate web-search queries to find the official websites of INDIVIDUAL volleyball CLUBS in '+country+'. Use the LOCAL language(s) of that country for the volleyball term (Italy: pallavolo; Germany/Austria/Switzerland: Volleyball; Poland: siatkowka; Spain: voleibol; France: volley-ball; Greece: petosfairisi). Combine the volleyball term with club words (club / societa / Verein / klub / academy / youth / sezione / asd) AND with major cities and regions. '+((cities&&cities.length)?('Use these cities: '+cities.join(', ')+'.'):'Choose the ~25 largest cities and main regions of the country yourself.')+' Produce about '+count+' DISTINCT queries, each likely to surface a single club own site (NOT federations, leagues, results/stats, news or directories). Respond ONLY with compact JSON {\"keywords\":[{\"q\":string,\"lang\":string}]} where lang is the 2-letter language code of q. No prose, no code fences.';
}
return [{json:{target,country,count,breadth,focus,prompt}}];

// Parse the model output into candidate keywords; return them (no persistence).
const meta=$('Build prompt').first().json;
let kws=[];
try{ const resp=$json; const txt=(resp&&resp.content&&resp.content[0]&&resp.content[0].text)||''; const o=JSON.parse(String(txt).replace(/```json/gi,'').replace(/```/g,'').trim()); kws=Array.isArray(o.keywords)?o.keywords:[]; }catch(e){}
const seen=new Set(); const candidates=[];
for(const k of kws){ const kw=String((k&&k.q)||'').trim(); if(!kw||seen.has(kw.toLowerCase()))continue; seen.add(kw.toLowerCase()); candidates.push({keyword:kw,lang:String((k&&k.lang)||'').trim().slice(0,5)}); }
return [{json:{target:meta.target,country:meta.country,count:candidates.length,candidates}}];
